import { useEffect, useMemo, useState } from "react";
import API, { getApiError } from "../services/api";
import { formatDisplayDate } from "../utils/membership";

const currencyFormatter = new Intl.NumberFormat("en-IN", {
  style: "currency",
  currency: "INR",
  maximumFractionDigits: 0
});

function getMonthKey(value) {
  if (!value) {
    return "";
  }

  return value.slice(0, 7);
}

function formatMonthLabel(monthKey) {
  if (!monthKey) {
    return "Unknown";
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "long",
    year: "numeric"
  }).format(new Date(`${monthKey}-01T00:00:00`));
}

function formatCurrency(value) {
  return currencyFormatter.format(value || 0);
}

export default function Payments() {
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedMonth, setSelectedMonth] = useState("");

  useEffect(() => {
    const loadCustomers = async () => {
      setLoading(true);
      setError("");

      try {
        const response = await API.get("/customers");
        setCustomers(response.data);
      } catch (requestError) {
        setError(getApiError(requestError, "Unable to load payment details."));
      } finally {
        setLoading(false);
      }
    };

    loadCustomers();
  }, []);

  const paymentMonths = useMemo(() => {
    const grouped = customers.reduce((months, customer) => {
      const monthKey = getMonthKey(customer.planStart);

      if (!monthKey) {
        return months;
      }

      if (!months[monthKey]) {
        months[monthKey] = {
          monthKey,
          label: formatMonthLabel(monthKey),
          totalAmount: 0,
          customerCount: 0,
          payments: []
        };
      }

      months[monthKey].totalAmount += Number(customer.amountPaid) || 0;
      months[monthKey].customerCount += 1;
      months[monthKey].payments.push(customer);

      return months;
    }, {});

    return Object.values(grouped).sort((left, right) =>
      right.monthKey.localeCompare(left.monthKey)
    );
  }, [customers]);

  useEffect(() => {
    if (!paymentMonths.length) {
      setSelectedMonth("");
      return;
    }

    if (!selectedMonth || !paymentMonths.some((month) => month.monthKey === selectedMonth)) {
      setSelectedMonth(paymentMonths[0].monthKey);
    }
  }, [paymentMonths, selectedMonth]);

  const selectedMonthData =
    paymentMonths.find((month) => month.monthKey === selectedMonth) || null;

  const selectedPayments = selectedMonthData
    ? [...selectedMonthData.payments].sort((left, right) =>
        right.planStart.localeCompare(left.planStart)
      )
    : [];

  const averagePayment = selectedMonthData
    ? Math.round(selectedMonthData.totalAmount / selectedMonthData.customerCount)
    : 0;

  const highestPayment = selectedPayments.reduce(
    (max, customer) => Math.max(max, Number(customer.amountPaid) || 0),
    0
  );

  const monthlyPeak = paymentMonths.reduce(
    (max, month) => Math.max(max, month.totalAmount),
    0
  );

  return (
    <div className="page-stack">
      <section className="page-heading">
        <div>
          <span className="eyebrow">Collections overview</span>
          <h2>Monthly payment details</h2>
          <p>Track member payments month by month using each member&apos;s plan start date.</p>
        </div>
      </section>

      {error ? <div className="status-banner status-banner--error">{error}</div> : null}

      <section className="summary-strip">
        <div>
          <strong>
            {loading
              ? "..."
              : selectedMonthData
                ? formatCurrency(selectedMonthData.totalAmount)
                : formatCurrency(0)}
          </strong>
          <span>Collected in selected month</span>
        </div>
        <div>
          <strong>{loading ? "..." : selectedMonthData?.customerCount || 0}</strong>
          <span>Payments recorded</span>
        </div>
        <div>
          <strong>{loading ? "..." : formatCurrency(averagePayment)}</strong>
          <span>Average payment</span>
        </div>
        <div>
          <strong>{loading ? "..." : formatCurrency(highestPayment)}</strong>
          <span>Highest single payment</span>
        </div>
      </section>

      <section className="panel-grid">
        <article className="panel-card">
          <div className="panel-card__header">
            <h3>Monthly collections</h3>
            {paymentMonths.length ? (
              <label className="field field--compact">
                <span>Select month</span>
                <select
                  value={selectedMonth}
                  onChange={(event) => setSelectedMonth(event.target.value)}
                >
                  {paymentMonths.map((month) => (
                    <option key={month.monthKey} value={month.monthKey}>
                      {month.label}
                    </option>
                  ))}
                </select>
              </label>
            ) : null}
          </div>

          {loading ? (
            <div className="panel-empty">Loading monthly collections...</div>
          ) : paymentMonths.length ? (
            <div className="payments-month-list">
              {paymentMonths.map((month) => {
                const ratio = monthlyPeak ? (month.totalAmount / monthlyPeak) * 100 : 0;

                return (
                  <button
                    key={month.monthKey}
                    type="button"
                    className={`payment-month-card${
                      selectedMonth === month.monthKey ? " is-active" : ""
                    }`}
                    onClick={() => setSelectedMonth(month.monthKey)}
                  >
                    <div className="payment-month-card__header">
                      <strong>{month.label}</strong>
                      <span>{month.customerCount} payments</span>
                    </div>
                    <div className="payment-month-card__bar">
                      <div style={{ width: `${Math.max(ratio, 8)}%` }} />
                    </div>
                    <p>{formatCurrency(month.totalAmount)}</p>
                  </button>
                );
              })}
            </div>
          ) : (
            <div className="panel-empty">
              No payment data yet. Payments will appear here after customers are added.
            </div>
          )}
        </article>

        <article className="panel-card">
          <div className="panel-card__header">
            <h3>Selected month snapshot</h3>
            {selectedMonthData ? (
              <span className="badge badge--success">{selectedMonthData.label}</span>
            ) : null}
          </div>

          {loading ? (
            <div className="panel-empty">Loading snapshot...</div>
          ) : selectedMonthData ? (
            <div className="payments-snapshot">
              <div className="pressure-card pressure-card--warning">
                <strong>{formatCurrency(selectedMonthData.totalAmount)}</strong>
                <span>Total collections</span>
              </div>
              <div className="pressure-card pressure-card--danger">
                <strong>{selectedMonthData.customerCount}</strong>
                <span>Members paid</span>
              </div>
              <div className="info-card__row">
                <span>Average ticket size</span>
                <strong>{formatCurrency(averagePayment)}</strong>
              </div>
              <div className="info-card__row">
                <span>Top payment</span>
                <strong>{formatCurrency(highestPayment)}</strong>
              </div>
            </div>
          ) : (
            <div className="panel-empty">Choose a month to inspect payment details.</div>
          )}

          <p className="panel-note">
            Monthly totals are grouped by each member&apos;s <strong>plan start</strong> date.
          </p>
        </article>
      </section>

      <section className="panel-card">
        <div className="panel-card__header">
          <h3>Payment entries</h3>
          {selectedMonthData ? (
            <span className="badge badge--neutral">{selectedMonthData.label}</span>
          ) : null}
        </div>

        {loading ? (
          <div className="panel-empty">Loading payment entries...</div>
        ) : selectedPayments.length ? (
          <div className="table-wrap">
            <table className="data-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Member</th>
                  <th>Plan</th>
                  <th>Paid on</th>
                  <th>Plan ends</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {selectedPayments.map((customer) => (
                  <tr key={customer.customerId}>
                    <td>#{customer.customerId}</td>
                    <td>
                      <div className="table-member">
                        <strong>{customer.fullName}</strong>
                        <span>{customer.phone}</span>
                      </div>
                    </td>
                    <td>{customer.plan}</td>
                    <td>{formatDisplayDate(customer.planStart)}</td>
                    <td>{formatDisplayDate(customer.planEnd)}</td>
                    <td>{formatCurrency(customer.amountPaid)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="panel-empty">No payments recorded for the selected month.</div>
        )}
      </section>
    </div>
  );
}
